import logo from "../assets/logo.png";
export default function Footer() {
  const styles = {
    footer: {
      backgroundColor: "#32d5d5",
      color: "white",
      padding: "1rem 2rem",
    },

    columns: {
      display: "flex",
      justifyContent: "space-between",
      flexWrap: "wrap",
      gap: "0.5rem",
    },

    title: {
      fontSize: "1rem",
      marginBottom: "0.5rem",
      fontWeight: "700",
    },

    logo: {
      fontSize: "1.7rem",
      fontWeight: "bold",
      marginBottom: "2rem",
    },

    info: {
      fontSize: "0.9rem",
      marginBottom: "1rem",
    },

    link: {
      color: "white",
      textDecoration: "none",
    },

    copy: {
      textAlign: "center",
      fontSize: "1rem",
      opacity: 0.9,
    },
  };

  return (
    <footer style={styles.footer}>
      <div style={styles.columns}>
        <div>
          <div
            style={{
              display: "flex",
              flexDirection: "column",
              alignItems: "center",
            }}
          >
            <img
              src={logo}
              alt="Smile Together"
              style={{
                width: "150px",
                marginBottom: "1rem",
              }}
            />

            <div style={styles.logo}></div>
          </div>
        </div>
        <div>
          <h3 style={styles.title}>Navegación</h3>

          <p style={styles.info}>Home</p>
          <p style={styles.info}>Tienda</p>
          <p style={styles.info}>Contacto</p>
        </div>

        <div>
          <h3 style={styles.title}>Contacto</h3>

          <p style={styles.info}>
            <a href="mailto:anima2026@proyectofinal.com" style={styles.link}>
              anima2026@proyectofinal.com
            </a>
          </p>

          <p style={styles.info}>
            <a
              href="https://wa.me/5980000000"
              target="_blank"
              rel="noreferrer"
              style={styles.link}
            >
              +598 990000000
            </a>
          </p>
        </div>

        <div>
          <h3 style={styles.title}>Ubicación</h3>

          <p style={styles.info}>Av. Ánima 2026</p>

          <p style={styles.info}>Esquina Finest</p>
        </div>
      </div>

      <hr
        style={{
          margin: "0.6rem 0",
          border: "0.3px solid rgba(255,255,255,.3)",
        }}
      />

      <p style={styles.copy}>
        © {new Date().getFullYear()} SmileTogether. Todos los derechos
        reservados.
      </p>
    </footer>
  );
}
